// Split find output into individual file path items
const stdout = $input.first().json.stdout || '';
const lines = stdout.split('\n').filter(line => line.trim().length > 0);

if (lines.length === 0) {
  // No new files found — return empty to stop pipeline
  return [];
}

const items = lines.map(filePath => ({
  json: {
    filePath: filePath.trim(),
    fileName: filePath.trim().split('/').pop()
  }
}));

return items;

// Parse ffprobe JSON output and extract existing tags
const items = [];

for (const item of $input.all()) {
  const filePath = $('Split Into Individual Files').item.json.filePath;
  const fileName = $('Split Into Individual Files').item.json.fileName;
  const stdout = item.json.stdout || '{}';

  let tags = {};
  let duration = 0;
  let bitrate = 0;

  try {
    const ffprobeData = JSON.parse(stdout);
    if (ffprobeData.format) {
      tags = ffprobeData.format.tags || {};
      duration = parseFloat(ffprobeData.format.duration) || 0;
      bitrate = parseInt(ffprobeData.format.bit_rate, 10) || 0;
    }
  } catch (e) {
    // ffprobe parse error — continue with empty tags
    tags = {};
  }

  // Normalize tag keys to lowercase for consistency
  const normalizedTags = {};
  for (const [key, value] of Object.entries(tags)) {
    normalizedTags[key.toLowerCase()] = value;
  }

  items.push({
    json: {
      filePath,
      fileName,
      artist: normalizedTags.artist || normalizedTags.albumartist || '',
      album: normalizedTags.album || '',
      title: normalizedTags.title || '',
      genre: normalizedTags.genre || '',
      date: normalizedTags.date || normalizedTags.year || '',
      trackNumber: normalizedTags.tracknumber || normalizedTags.track || '',
      duration: Math.round(duration),
      bitrate,
      existingTags: normalizedTags,
      hasGenre: !!(normalizedTags.genre && normalizedTags.genre.trim().length > 0)
    }
  });
}

return items;

