// Parse LLM classification response
const items = [];

for (const item of $input.all()) {
  const llmResponse = item.json;
  const trackMeta = $('Parse Existing Tags').item.json;

  let classification;
  try {
    const content = llmResponse.choices[0].message.content;
    if (typeof content === 'string') {
      // Strip markdown code fences if present
      const cleaned = content.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
      classification = JSON.parse(cleaned);
    } else {
      classification = content;
    }
  } catch (e) {
    classification = {
      genre: '',
      subgenre: '',
      mood: '',
      confidence: 0.0
    };
  }

  // Normalize confidence
  let confidence = parseFloat(classification.confidence);
  if (isNaN(confidence)) confidence = 0.0;
  if (confidence < 0) confidence = 0.0;
  if (confidence > 1) confidence = 1.0;

  items.push({
    json: {
      filePath: trackMeta.filePath,
      fileName: trackMeta.fileName,
      artist: trackMeta.artist,
      album: trackMeta.album,
      title: trackMeta.title,
      existingGenre: trackMeta.genre,
      genre: classification.genre || '',
      subgenre: classification.subgenre || '',
      mood: classification.mood || '',
      confidence,
      hadGenre: trackMeta.hasGenre
    }
  });
}

return items;

// Aggregate results for batch summary
const allClassified = $('Parse LLM Classification').all();
const updated = $('metaflac — Update Tags').all();
const skippedItems = $('IF Confidence > 0.7').all();

let totalScanned = allClassified.length;
let totalUpdated = updated.length;
let totalSkipped = totalScanned - totalUpdated;

// Build genre breakdown
const genreCounts = {};
for (const item of allClassified) {
  const genre = item.json.genre || 'Unknown';
  genreCounts[genre] = (genreCounts[genre] || 0) + 1;
}

const genreBreakdown = Object.entries(genreCounts)
  .sort((a, b) => b[1] - a[1])
  .map(([genre, count]) => `  ${genre}: ${count}`)
  .join('\n');

// Build summary
const summary = [
  `Music Library Batch — ${new Date().toISOString().split('T')[0]}`,
  `Scanned: ${totalScanned} files`,
  `Updated: ${totalUpdated} (confidence > 0.7)`,
  `Skipped: ${totalSkipped} (low confidence)`,
  '',
  'Genre breakdown:',
  genreBreakdown
].join('\n');

return [{
  json: {
    summary,
    totalScanned,
    totalUpdated,
    totalSkipped,
    genreCounts,
    timestamp: new Date().toISOString()
  }
}];

// Low-confidence items — log but don't update
const items = [];

for (const item of $input.all()) {
  items.push({
    json: {
      ...item.json,
      skipped: true,
      reason: `Confidence ${item.json.confidence} <= 0.7 threshold`
    }
  });
}

return items;

// Filter albums that don't have descriptions/comments
const items = [];
const response = $input.first().json;

// Navidrome Subsonic API nests under subsonic-response.albumList2.album
let albums = [];
try {
  albums = response['subsonic-response']?.albumList2?.album || [];
} catch (e) {
  // Try alternate response shapes
  if (Array.isArray(response)) {
    albums = response;
  } else if (response.albumList2) {
    albums = response.albumList2.album || [];
  }
}

for (const album of albums) {
  // Skip albums that already have a comment/description
  if (album.comment && album.comment.trim().length > 0) {
    continue;
  }

  items.push({
    json: {
      albumId: album.id,
      albumName: album.name || album.title || '',
      artist: album.artist || album.albumArtist || '',
      genre: album.genre || '',
      year: album.year || '',
      songCount: album.songCount || 0,
      duration: album.duration || 0
    }
  });
}

return items.length > 0 ? items : [];

