// Extract the generated description from LLM response
const items = [];

for (const item of $input.all()) {
  const llmResponse = item.json;
  const albumMeta = $('Filter Albums Without Descriptions').item.json;

  let description = '';
  try {
    description = llmResponse.choices[0].message.content.trim();
    // Remove wrapping quotes if present
    if (description.startsWith('"') && description.endsWith('"')) {
      description = description.slice(1, -1);
    }
  } catch (e) {
    description = '';
  }

  if (description.length > 0) {
    items.push({
      json: {
        albumId: albumMeta.albumId,
        albumName: albumMeta.albumName,
        artist: albumMeta.artist,
        description
      }
    });
  }
}

return items;
